request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?choreo
  (COUNT(*) AS ?cyclicWitnesses)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "1ad939eef40c461dafae27f75a0586d3" ;
         tai:belongsTo ?org .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .

  # adjacency cycle of length 2 using sequence flows: A->B and B->A
  ?a tai:belongsTo ?choreo ;
     bbo:name ?aName .
  ?b tai:belongsTo ?choreo ;
     bbo:name ?bName .

  ?e1 a bbo:SequenceFlow ;
      bbo:has_sourceRef ?a ;
      bbo:has_targetRef ?b .
  ?e2 a bbo:SequenceFlow ;
      bbo:has_sourceRef ?b ;
      bbo:has_targetRef ?a .
}
GROUP BY ?choreo
LIMIT 25
